// ────────────────────────────────────────────
// Prep T5 Body (manual create from admin dashboard)
// ⚠️ Per 2026-04-18 audit + decision (Option B):
//   • T5.Customer is a LOOKUP field — resolved via Machine link, DO NOT write.
// ⚠️ Per 2026-04-20 live test (rental-cron bug #5):
//   • Lark Link write format = ["rec..."] NOT { link_record_ids: [...] } (legacy object)
//     legacy format = LinkFieldConvFail code 1254067 ทันที
//
// 📌 TECH DEBT (tracked 2026-04-18):
//   Dashboard form ต้องเพิ่ม Machine selector → ส่ง machine_record_id →
//   เพิ่ม Machine write ตรงนี้ → T5.Customer Lookup จะ resolve ได้อัตโนมัติ
//   ปัจจุบัน dashboard ยังไม่ส่ง machine_record_id จึง skip Machine write ไปก่อน
// ────────────────────────────────────────────
const token = $('Get Token [CJ]').first().json.tenant_access_token;
const src   = $('Parse Body').first().json;

let scheduledMs = null;
if (src.scheduled_date) {
  // Bangkok midnight (ไม่งั้น server UTC จะเพี้ยน -7h)
  try { scheduledMs = new Date(src.scheduled_date + 'T00:00:00+07:00').getTime(); } catch(e) {}
  if (isNaN(scheduledMs)) {
    try { scheduledMs = new Date(src.scheduled_date).getTime(); } catch(e) {}
  }
}

const fields = {};
fields['Status'] = 'นัดแล้ว';
// Job Type is MultiSelect (verified 2026-04-20) → must be array even for single value
if (src.job_type)    fields['Job Type']       = Array.isArray(src.job_type) ? src.job_type : [src.job_type];
if (src.priority)    fields['Priority']       = src.priority;
if (src.problem)     fields['Defect']         = src.problem;
if (src.note)        fields['Note']           = src.note;
fields['Source'] = src.source;
if (scheduledMs)     fields['Scheduled Date'] = scheduledMs;
// ❌ Removed: Customer write — T5.Customer = Lookup (silent-drop anyway).
// Technician Link write format = ["rec..."] (array of ID strings)
// ⚠️ เดิมใช้ { link_record_ids: [...] } ตามคอมเมนต์เก่า — format นั้นคืน LinkFieldConvFail
if (src.tech_record_id)     fields['Technician']  = [src.tech_record_id];

return [{ json: { ...src, lark_token: token, createBody: JSON.stringify({ fields }) } }];

