// ⚠️ Fixed 2026-04-20:
//    เดิมอ่าน 'T4 Refs' (Text field — ไม่มีใน T5 schema) → t4Refs='' เสมอ → isCarePlan=false เสมอ
//    → branch Update T4 ไม่เคยรัน → Last Done Date ไม่ update → เครื่องถูกนัดซ้ำไม่รู้จบ
//    T5 schema จริงใช้ 'Related Care Plan' (DuplexLink → T4).
const res = $input.first().json;
const items = res.data && res.data.items ? res.data.items : [];
const record_id = items.length > 0 ? items[0].record_id : '';
const src = $('Parse Complete Body').first().json;
const token = $('Get Token [Complete]').first().json.tenant_access_token;
const fields = {
  'Status': 'เสร็จแล้ว',
  'Parts Used': src.parts_text || '',
  'Note': src.notes || '',
  'Photo Count': src.photo_count || 0
};
// Extract Related Care Plan (DuplexLink) + Source Ref ID for CarePlan loop closure
function txt(v) { if (!v) return ''; if (typeof v === 'string') return v; if (v.text) return v.text; if (Array.isArray(v)) return v.map(i => typeof i === 'string' ? i : (i.text||'')).join(','); return ''; }
function extractLinkedIds(v) {
  if (!v) return [];
  const arr = Array.isArray(v) ? v : (Array.isArray(v.value) ? v.value : []);
  return arr.map(r => {
    if (typeof r === 'string') return '';
    return r.record_id || (Array.isArray(r.record_ids) ? r.record_ids[0] : r.record_ids) || '';
  }).filter(Boolean);
}
let t4RefIds = [];
let sourceRefId = '';
if (items.length > 0) {
  const f = items[0].fields || {};
  t4RefIds = extractLinkedIds(f['Related Care Plan']);
  sourceRefId = txt(f['Source Ref ID'] || '');
}
const isCarePlan = (sourceRefId === 'AUTO-CAREPLAN' && t4RefIds.length > 0);
return [{ json: { ...src, record_id, lark_token: token, updateBody: JSON.stringify({ fields }), t4_refs: t4RefIds, source_ref_id: sourceRefId, is_careplan: isCarePlan } }];

// ────────────────────────────────────────────
// Search T4 records referenced by this T5
// เพื่อดึง Interval มาคำนวณ Next Due Date ใหม่
// ⚠️ ห้ามระบุ field_names — Lark จะตัด primary field ทิ้ง
// ⚠️ 2026-04-20: t4_refs เปลี่ยนเป็น array แล้ว (เดิมเป็น comma-string)
// ────────────────────────────────────────────
const data = $('Prep Update T5 Complete').first().json;
const t4Refs = Array.isArray(data.t4_refs) ? data.t4_refs : (typeof data.t4_refs === 'string' ? data.t4_refs.split(',').map(s => s.trim()).filter(Boolean) : []);
const token = data.lark_token;

// Lark: search by record IDs — use __id__ filter
const searchBody = JSON.stringify({
  filter: {
    conjunction: 'or',
    conditions: t4Refs.map(id => ({ field_name: '__id__', operator: 'is', value: [id] }))
  },
  page_size: 20
});

return [{ json: { t4_refs: t4Refs, lark_token: token, searchBody, completed_at: data.completed_at } }];

// ────────────────────────────────────────────
// Update T4 after service completion
// ⚠️ Per 2026-04-18 audit:
//   • Next Due Date is a FORMULA → cannot write. Lark recomputes automatically
//     from Last Done Date + Planned Interval (Months) once we update Last Done Date.
//   • Interval (Months) field does NOT exist in T4 → use Planned Interval (Months) only.
//   • Service Item is DuplexLink → read via Filter Stage (Text) instead.
// ⚠️ Per 2026-04-20 live test (rental-cron bugs #2, #4):
//   • Lark Date READ = ms number → ใช้ dateStr() ไม่ใช่ txt().split('T')[0]
//   • Lark Date WRITE = ms number → ใช้ toMs() ไม่ใช่ 'YYYY-MM-DD' string
// Split → 1 item per T4 update.
// ────────────────────────────────────────────
const res = $input.first().json;
const items = (res.data && res.data.items) || [];
const prevData = $('Prep Search T4 Refs').first().json;
const completedAt = prevData.completed_at || new Date().toISOString();
const token = prevData.lark_token;

function numVal(v) {
  if (typeof v === 'number') return v;
  if (!v) return 0;
  const n = Number(typeof v === 'string' ? v : (v.text || v.value || 0));
  return isNaN(n) ? 0 : n;
}

function txt(v) {
  if (v === null || v === undefined) return '';
  if (typeof v === 'string') return v;
  if (typeof v === 'number') return String(v);
  if (v.text) return v.text;
  if (Array.isArray(v) && v[0]) { const x = v[0]; return typeof x === 'string' ? x : (x.text || x.name || ''); }
  return '';
}

// Lark Date field = Unix ms number. Convert to YYYY-MM-DD in Bangkok TZ.
function dateStr(v) {
  if (v === null || v === undefined || v === '') return '';
  if (typeof v === 'number') {
    const bkk = new Date(v + 7 * 3600 * 1000);
    const yyyy = bkk.getUTCFullYear();
    const mm = String(bkk.getUTCMonth() + 1).padStart(2, '0');
    const dd = String(bkk.getUTCDate()).padStart(2, '0');
    return yyyy + '-' + mm + '-' + dd;
  }
  const s = typeof v === 'string' ? v : txt(v);
  if (!s) return '';
  return s.split('T')[0].replace(/\//g, '-');
}

// Lark Date write = ms timestamp (Bangkok midnight)
function toMs(dateStrVal) {
  if (!dateStrVal) return null;
  return new Date(dateStrVal + 'T00:00:00+07:00').getTime();
}

// Calculate months between two YYYY-MM-DD dates (rounded)
function monthsBetween(oldStr, newStr) {
  if (!oldStr || !newStr) return 0;
  const a = new Date(oldStr + 'T00:00:00');
  const b = new Date(newStr + 'T00:00:00');
  if (isNaN(a) || isNaN(b)) return 0;
  const days = (b - a) / 86400000;
  return Math.round(days / 30.44); // avg month length
}

// Parse JSON array from string, safely
function parseIntervals(s) {
  if (!s) return [];
  try {
    const arr = JSON.parse(typeof s === 'string' ? s : txt(s));
    return Array.isArray(arr) ? arr.filter(n => typeof n === 'number') : [];
  } catch(e) { return []; }
}

const updates = items.map(it => {
  const f = it.fields || {};
  // Planned Interval is the template baseline + single source of truth for Formula.
  // Default 3 months as sane fallback if template value missing.
  const interval = numVal(f['Planned Interval (Months)']) || 3;
  // completedAt อาจเป็น ISO ยาว → เอาเฉพาะวันที่ (server UTC ISO ยังใกล้พอสำหรับการคำนวณห่างเดือน)
  const completedDate = completedAt.split('T')[0];

  // ── Actual Interval Tracking ──
  // oldLastDone = previous completion date (null on first run)
  // ⚠️ Last Done Date เป็น Date field = ms number → dateStr() แปลงก่อน
  const oldLastDone = dateStr(f['Last Done Date']);
  const actualInterval = monthsBetween(oldLastDone, completedDate);

  // Keep last 3 actual intervals as JSON array string (for trend analysis / override audit)
  const prevIntervals = parseIntervals(txt(f['Last 3 Actual Intervals']));
  let newIntervals = prevIntervals;
  if (actualInterval > 0) {
    newIntervals = [...prevIntervals, actualInterval].slice(-3);
  }

  // ⚠️ DO NOT write 'Next Due Date' — it's a Formula (silent-drop on write).
  // Lark recomputes: Next Due Date = Last Done Date + Planned Interval (Months).
  // ⚠️ Last Done Date เป็น Date field → write = ms (ไม่ใช่ 'YYYY-MM-DD' ไม่งั้น DatetimeFieldConvFail)
  const updateFields = {
    'Last Done Date': toMs(completedDate),
    'Last 3 Actual Intervals': JSON.stringify(newIntervals)
  };

  return {
    record_id: it.record_id,
    stage_number: numVal(f['Stage Number']),
    filter_name: txt(f['Filter Stage']),
    old_last_done: oldLastDone,
    new_last_done: completedDate,
    interval: interval,
    actual_interval: actualInterval,
    last_3_actual: newIntervals,
    lark_token: token,
    updateBody: JSON.stringify({ fields: updateFields })
  };
}).filter(u => u.record_id);

if (updates.length === 0) return [{ json: { t4_updated: 0 } }];
return updates.map(u => ({ json: u }));

