const items = $input.first().json.data && $input.first().json.data.items ? $input.first().json.data.items : [];
function txt(v) {
  if (!v) return '';
  if (typeof v === 'string') return v;
  if (v.text) return v.text;
  if (v.value) return v.value;
  if (Array.isArray(v) && v[0]) return txt(v[0]);
  return '';
}
function fromMs(ms) {
  if (!ms) return '';
  return new Date(ms).toISOString().split('T')[0];
}
const bookings = items.map(r => {
  const f = r.fields || {};
  let editLog = [];
  try { editLog = JSON.parse(txt(f['Edit Log']) || '[]'); } catch(e) {}
  return {
    booking_id:    r.record_id,
    customer_name: txt(f['Customer Name']),
    appoint_date:  fromMs(f['Appoint Date']),
    sched_date:    fromMs(f['Sched Date']),
    sched_time:    txt(f['Sched Time']),
    job_type:      txt(f['Job Type']),
    priority:      txt(f['Priority']) || 'Med',
    tech_name:     txt(f['Tech Name']),
    notes:         txt(f['Notes']),
    status:        txt(f['Status']) || 'active',
    cancel_reason: txt(f['Cancel Reason']),
    notify_date:   fromMs(f['Notify Date']),
    created_by:    txt(f['Created By']),
    created_at:    txt(f['Created At']),
    edit_log:      editLog
  };
});
return [{ json: bookings }];

const token = $input.first().json.tenant_access_token;
const body = $('Webhook Create Booking').first().json.body || $('Webhook Create Booking').first().json;
function toMs(dateStr) { if (!dateStr) return null; return new Date(dateStr + 'T00:00:00').getTime(); }
const fields = {};
if (body.customer_name) fields['Customer Name'] = body.customer_name;
if (body.appoint_date)  fields['Appoint Date']  = toMs(body.appoint_date);
if (body.sched_date)    fields['Sched Date']    = toMs(body.sched_date);
if (body.sched_time)    fields['Sched Time']    = body.sched_time;
if (body.job_type)      fields['Job Type']      = body.job_type;
if (body.priority)      fields['Priority']      = body.priority;
if (body.tech_name)     fields['Tech Name']     = body.tech_name;
if (body.notes)         fields['Notes']         = body.notes;
fields['Status']      = 'active';
if (body.notify_date)   fields['Notify Date']   = toMs(body.notify_date);
fields['Created By']  = body.created_by || 'Admin';
fields['Created At']  = new Date().toISOString();
fields['Edit Log']    = '[]';
return [{ json: { lark_token: token, createBody: JSON.stringify({ fields }) } }];

const rec = $input.first().json.data && $input.first().json.data.record ? $input.first().json.data.record : {};
const body = $('Parse Edit Body').first().json;
const token = $('Get Token [EB]').first().json.tenant_access_token;
const f = rec.fields || {};
function txt(v) { if (!v) return ''; if (typeof v === 'string') return v; if (v.text) return v.text; return ''; }
function toMs(d) { if (!d) return null; return new Date(d + 'T00:00:00').getTime(); }
let editLog = [];
try { editLog = JSON.parse(txt(f['Edit Log']) || '[]'); } catch(e) {}
editLog.push({ edited_by: body.edited_by, edited_at: body.edited_at, edit_reason: body.edit_reason });
const fields = {};
if (body.sched_date)  fields['Sched Date']  = toMs(body.sched_date);
if (body.sched_time)  fields['Sched Time']  = body.sched_time;
if (body.tech_name)   fields['Tech Name']   = body.tech_name;
if (body.notify_date) fields['Notify Date'] = toMs(body.notify_date);
fields['Edit Log'] = JSON.stringify(editLog);
return [{ json: { lark_token: token, booking_id: body.booking_id, updateBody: JSON.stringify({ fields }) } }];

